# =========================================================
# 07_results_summary.R
# English summary of key bibliometric results
# =========================================================
#
# Inputs
# ------
# outputs/tables/*.csv generated by previous scripts
# processed_data/base_unificada.rds
#
# Outputs
# -------
# outputs/reports/results_summary.txt
# =========================================================

library(dplyr)

cat("Generating textual summary of results...\n")

# ---------------------------------------------------------
# 1. Load data and output tables
# ---------------------------------------------------------
if (!file.exists("processed_data/base_unificada.rds")) {
  stop("processed_data/base_unificada.rds not found. Run the previous scripts first.")
}

M <- readRDS("processed_data/base_unificada.rds")

read_optional_csv <- function(path) {
  if (file.exists(path)) read.csv(path, stringsAsFactors = FALSE) else NULL
}

annual <- read_optional_csv("outputs/tables/annual_scientific_production.csv")
authors <- read_optional_csv("outputs/tables/top_authors.csv")
sources <- read_optional_csv("outputs/tables/top_sources.csv")
keywords <- read_optional_csv("outputs/tables/top_keywords.csv")
countries <- read_optional_csv("outputs/tables/publications_by_country.csv")

# ---------------------------------------------------------
# 2. Build a concise English report
# ---------------------------------------------------------
report_lines <- c(
  "Bibliometric Results Summary",
  "============================",
  "",
  paste0("Final bibliometric corpus: ", nrow(M), " documents."),
  paste0("Timespan: ", min(M$PY_NUM, na.rm = TRUE), "-", max(M$PY_NUM, na.rm = TRUE), "."),
  ""
)

if (!is.null(annual) && nrow(annual) > 0) {
  peak <- annual[which.max(annual$Publications), ]
  report_lines <- c(
    report_lines,
    "Annual scientific production:",
    paste0("- Peak year: ", peak$PY_NUM, " with ", peak$Publications, " publications."),
    paste0("- Total publications in the plotted time series: ", sum(annual$Publications), "."),
    ""
  )
}

if (!is.null(authors) && nrow(authors) > 0) {
  top_authors <- paste0(authors$AU[1:min(3, nrow(authors))], " (", authors$Publications[1:min(3, nrow(authors))], ")", collapse = "; ")
  report_lines <- c(
    report_lines,
    "Most productive authors:",
    paste0("- Top contributors: ", top_authors, "."),
    ""
  )
}

if (!is.null(sources) && nrow(sources) > 0) {
  top_sources <- paste0(sources$SO[1:min(3, nrow(sources))], " (", sources$Publications[1:min(3, nrow(sources))], ")", collapse = "; ")
  report_lines <- c(
    report_lines,
    "Most relevant sources:",
    paste0("- Main publication venues: ", top_sources, "."),
    ""
  )
}

if (!is.null(keywords) && nrow(keywords) > 0) {
  top_keywords <- paste0(keywords$KW[1:min(5, nrow(keywords))], " (", keywords$Frequency[1:min(5, nrow(keywords))], ")", collapse = "; ")
  report_lines <- c(
    report_lines,
    "Keyword analysis:",
    paste0("- Most frequent keywords: ", top_keywords, "."),
    "- The keyword distribution indicates a strong concentration around IoT, security, computing architectures, cloud computing, and edge computing.",
    ""
  )
}

if (!is.null(countries) && nrow(countries) > 0) {
  top_countries <- paste0(countries$Country[1:min(5, nrow(countries))], " (", countries$Publications[1:min(5, nrow(countries))], ")", collapse = "; ")
  report_lines <- c(
    report_lines,
    "Country analysis:",
    paste0("- Most represented countries: ", top_countries, "."),
    ""
  )
}

report_lines <- c(
  report_lines,
  "Methodological note:",
  "- The pipeline integrates multi-source import, data cleaning, temporal filtering, deduplication, bibliometric analysis, visual analytics, country normalization, and a reproducible results summary.",
  "- The ProKnow-C prioritization and technical synthesis are executed separately from the proknowc/ directory."
)

writeLines(report_lines, "outputs/reports/results_summary.txt", useBytes = TRUE)

cat("Results summary generated at outputs/reports/results_summary.txt\n")
